import React, { useEffect, useMemo, useState } from "react";
import "./App.css";
import Menu from "./Menu";
import Orders from "./Orders";
import Admin from "./Admin";

const API_BASE = "http://localhost:8080";

const UPI_QR_IMAGE =
  "https://upload.wikimedia.org/wikipedia/commons/thumb/f/f2/UPI-Logo-vector.svg/1200px-UPI-Logo-vector.svg.png";

const exactImageMap = {
  "Veg Frankie":
    "https://source.unsplash.com/900x600/?veg,wrap,roll",
  "Egg Frankie":
    "https://source.unsplash.com/900x600/?egg,wrap,roll",
  "Chicken Frankie":
    "https://source.unsplash.com/900x600/?chicken,wrap,roll",

  Tea:
    "https://source.unsplash.com/900x600/?tea",
  Coffee:
    "https://source.unsplash.com/900x600/?coffee",
  "Lime Juice":
    "https://source.unsplash.com/900x600/?lime,juice",

  "Veg Biryani":
    "https://source.unsplash.com/900x600/?veg,biryani",
  "Chicken Biryani":
    "https://source.unsplash.com/900x600/?chicken,biryani",
  "Egg Biryani":
    "https://source.unsplash.com/900x600/?egg,biryani",

  "Veg Maggi":
    "https://source.unsplash.com/900x600/?veg,noodles",
  "Egg Maggi":
    "https://source.unsplash.com/900x600/?egg,noodles",

  "Veg Sandwich":
    "https://source.unsplash.com/900x600/?veg,sandwich",
  "Egg Sandwich":
    "https://source.unsplash.com/900x600/?egg,sandwich",
  "Chicken Sandwich":
    "https://source.unsplash.com/900x600/?chicken,sandwich",

  "Veg Burger":
    "https://source.unsplash.com/900x600/?veg,burger",
  "Chicken Burger":
    "https://source.unsplash.com/900x600/?chicken,burger",

  "Veg Parota":
    "https://source.unsplash.com/900x600/?paratha,flatbread",
  "Chicken Parota":
    "https://source.unsplash.com/900x600/?chicken,paratha",

  Bonda:
    "https://source.unsplash.com/900x600/?bonda,indian,snack",
  Idli:
    "https://source.unsplash.com/900x600/?idli",
  Dosa:
    "https://source.unsplash.com/900x600/?dosa",
  Vada:
    "https://source.unsplash.com/900x600/?vada,indian,snack",
  "Masala Dosa":
    "https://source.unsplash.com/900x600/?masala,dosa",

  "Veg Meals":
    "https://source.unsplash.com/900x600/?veg,thali,meal",
  "Non-Veg Meals":
    "https://source.unsplash.com/900x600/?nonveg,meal,thali",

  "Egg Fried Rice":
    "https://source.unsplash.com/900x600/?egg,fried,rice",
  "Veg Fried Rice":
    "https://source.unsplash.com/900x600/?veg,fried,rice",
  "Chicken Fried Rice":
    "https://source.unsplash.com/900x600/?chicken,fried,rice",

  "Veg Noodles":
    "https://source.unsplash.com/900x600/?veg,noodles",
  "Egg Noodles":
    "https://source.unsplash.com/900x600/?egg,noodles",
  "Chicken Noodles":
    "https://source.unsplash.com/900x600/?chicken,noodles",

  "Chocolate Shake":
    "https://source.unsplash.com/900x600/?chocolate,milkshake",
  "Vanilla Shake":
    "https://source.unsplash.com/900x600/?vanilla,milkshake",

  "Mosambi Juice":
    "https://source.unsplash.com/900x600/?sweetlime,juice",
  "Grape Juice":
    "https://source.unsplash.com/900x600/?grape,juice",
  "Papaya Juice":
    "https://source.unsplash.com/900x600/?papaya,juice",

  "Mix Fruit Salad":
    "https://source.unsplash.com/900x600/?fruit,salad"
};

const categoryFallbackMap = {
  Frankie:
    "https://source.unsplash.com/900x600/?frankie,wrap",
  Beverages:
    "https://source.unsplash.com/900x600/?beverage,drink",
  Biryani:
    "https://source.unsplash.com/900x600/?biryani",
  Maggi:
    "https://source.unsplash.com/900x600/?noodles",
  Sandwich:
    "https://source.unsplash.com/900x600/?sandwich",
  Burger:
    "https://source.unsplash.com/900x600/?burger",
  Parota:
    "https://source.unsplash.com/900x600/?paratha",
  Tiffins:
    "https://source.unsplash.com/900x600/?south,indian,breakfast",
  Meals:
    "https://source.unsplash.com/900x600/?thali,meal",
  "Fried Rice":
    "https://source.unsplash.com/900x600/?fried,rice",
  Noodles:
    "https://source.unsplash.com/900x600/?noodles",
  Shakes:
    "https://source.unsplash.com/900x600/?milkshake",
  Juices:
    "https://source.unsplash.com/900x600/?fruit,juice",
  Salads:
    "https://source.unsplash.com/900x600/?salad"
};

const heroSlides = [
  {
    title: "Skip the queue. Pre-order your meal.",
    subtitle:
      "A clean and stylish college canteen system for faster ordering, smart pickup, and better student experience."
  },
  {
    title: "Quick checkout with payment and pickup slot.",
    subtitle:
      "Choose your payment method, order type, pickup slot, and see the estimated waiting time before placing the order."
  },
  {
    title: "Students order fast. Admin manages easily.",
    subtitle:
      "A simple canteen platform with menu browsing, cart handling, order tracking, and admin menu management."
  }
];

function getImageByFoodName(food) {
  const exactName = (food?.name || "").trim();
  const category = (food?.category || "").trim();

  if (exactImageMap[exactName]) {
    return exactImageMap[exactName];
  }

  if (categoryFallbackMap[category]) {
    return categoryFallbackMap[category];
  }

  if (food?.imageUrl && String(food.imageUrl).trim()) {
    return food.imageUrl;
  }

  return "https://source.unsplash.com/900x600/?food";
}

function getStatusClass(status) {
  const value = (status || "Pending").toLowerCase();

  if (value.includes("ready")) return "status-badge ready";
  if (value.includes("complete")) return "status-badge completed";
  if (value.includes("cancel")) return "status-badge cancelled";
  if (value.includes("prepar")) return "status-badge preparing";
  return "status-badge pending";
}

function App() {
  const [foods, setFoods] = useState([]);
  const [page, setPage] = useState("menu");
  const [category, setCategory] = useState("All");
  const [search, setSearch] = useState("");
  const [cart, setCart] = useState([]);
  const [showCheckout, setShowCheckout] = useState(false);
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(true);
  const [heroIndex, setHeroIndex] = useState(0);

  const [checkoutForm, setCheckoutForm] = useState({
    customerName: "",
    paymentMethod: "UPI",
    orderType: "Takeaway",
    pickupSlot: "12:30 PM - 12:45 PM",
    notes: ""
  });

  useEffect(() => {
    loadFoods();
  }, []);

  useEffect(() => {
    const timer = setInterval(() => {
      setHeroIndex((prev) => (prev + 1) % heroSlides.length);
    }, 4000);

    return () => clearInterval(timer);
  }, []);

  async function loadFoods() {
    setLoading(true);
    setMessage("");

    try {
      const response = await fetch(`${API_BASE}/foods`);
      if (!response.ok) throw new Error("Failed to fetch foods");

      const data = await response.json();
      setFoods(Array.isArray(data) ? data : []);
    } catch (error) {
      setFoods([]);
      setMessage("Unable to load food items from backend.");
    } finally {
      setLoading(false);
    }
  }

  const foodsWithImages = useMemo(() => {
    return foods.map((food, index) => ({
      ...food,
      displayImage: getImageByFoodName(food),
      rating: (4.1 + ((index % 7) * 0.1)).toFixed(1),
      prepTime: 8 + (index % 5) * 3
    }));
  }, [foods]);

  const categories = useMemo(() => {
    const allCategories = foodsWithImages
      .map((food) => food.category)
      .filter(Boolean);

    return ["All", ...new Set(allCategories)];
  }, [foodsWithImages]);

  const featuredFoods = useMemo(() => foodsWithImages.slice(0, 4), [foodsWithImages]);

  const filteredFoods = useMemo(() => {
    return foodsWithImages.filter((food) => {
      const categoryOk = category === "All" || food.category === category;
      const searchOk = (food.name || "").toLowerCase().includes(search.toLowerCase());
      return categoryOk && searchOk;
    });
  }, [foodsWithImages, category, search]);

  const totalItems = useMemo(() => {
    return cart.reduce((sum, item) => sum + item.quantity, 0);
  }, [cart]);

  const subtotal = useMemo(() => {
    return cart.reduce((sum, item) => sum + item.price * item.quantity, 0);
  }, [cart]);

  const packingFee = cart.length > 0 ? 8 : 0;
  const platformFee = cart.length > 0 ? 5 : 0;
  const gst = cart.length > 0 ? Math.round(subtotal * 0.05) : 0;
  const totalAmount = subtotal + packingFee + platformFee + gst;
  const waitingTime = totalItems > 0 ? 10 + totalItems * 4 : 0;

  function addToCart(food) {
    setMessage("");

    setCart((prevCart) => {
      const existing = prevCart.find((item) => item.id === food.id);

      if (existing) {
        return prevCart.map((item) =>
          item.id === food.id
            ? { ...item, quantity: item.quantity + 1 }
            : item
        );
      }

      return [...prevCart, { ...food, quantity: 1 }];
    });
  }

  function updateQuantity(id, change) {
    setCart((prevCart) =>
      prevCart
        .map((item) =>
          item.id === id
            ? { ...item, quantity: Math.max(0, item.quantity + change) }
            : item
        )
        .filter((item) => item.quantity > 0)
    );
  }

  function removeCartItem(id) {
    setCart((prevCart) => prevCart.filter((item) => item.id !== id));
  }

  function handleCheckoutChange(event) {
    const { name, value } = event.target;
    setCheckoutForm((prev) => ({
      ...prev,
      [name]: value
    }));
  }

  async function placeOrder() {
    if (cart.length === 0) {
      setMessage("Your cart is empty.");
      return;
    }

    if (!checkoutForm.customerName.trim()) {
      setMessage("Please enter student name before placing the order.");
      return;
    }

    try {
      for (const item of cart) {
        const payload = {
          foodName: item.name,
          quantity: Number(item.quantity),
          totalPrice: Number(item.price) * Number(item.quantity),
          status: "Pending",
          customerName: checkoutForm.customerName,
          paymentMethod: checkoutForm.paymentMethod,
          orderType: checkoutForm.orderType,
          pickupSlot: checkoutForm.pickupSlot,
          notes: checkoutForm.notes,
          waitingTime: waitingTime
        };

        const response = await fetch(`${API_BASE}/orders`, {
          method: "POST",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify(payload)
        });

        if (!response.ok) throw new Error("Failed to place order");
      }

      setMessage(
        `Order placed successfully. Estimated waiting time: ${waitingTime} mins.`
      );
      setCart([]);
      setShowCheckout(false);
      setPage("orders");

      setCheckoutForm({
        customerName: "",
        paymentMethod: "UPI",
        orderType: "Takeaway",
        pickupSlot: "12:30 PM - 12:45 PM",
        notes: ""
      });
    } catch (error) {
      setMessage("Failed to place order. Check backend connection.");
    }
  }

  return (
    <div className="app-shell">
      <header className="hero-banner">
        <div>
          <p className="eyebrow">COLLEGE CANTEEN PRE-ORDER SYSTEM</p>
          <h1>{heroSlides[heroIndex].title}</h1>
          <p className="hero-subtitle">{heroSlides[heroIndex].subtitle}</p>
        </div>

        <div className="hero-stats">
          <div className="stat-chip">
            <span>{foods.length}</span>
            <small>Food Items</small>
          </div>
          <div className="stat-chip">
            <span>{totalItems}</span>
            <small>Cart Items</small>
          </div>
          <div className="stat-chip">
            <span>{waitingTime || "--"}</span>
            <small>Wait (mins)</small>
          </div>
        </div>
      </header>

      <nav className="top-nav">
        <button
          className={`nav-btn ${page === "menu" ? "active" : ""}`}
          onClick={() => setPage("menu")}
        >
          Menu
        </button>

        <button
          className={`nav-btn ${page === "orders" ? "active" : ""}`}
          onClick={() => setPage("orders")}
        >
          Orders
        </button>

        <button
          className={`nav-btn ${page === "admin" ? "active" : ""}`}
          onClick={() => setPage("admin")}
        >
          Dashboard
        </button>

        <button className="cart-pill" onClick={() => setShowCheckout(true)}>
          Cart <span>{totalItems}</span>
        </button>
      </nav>

      {message && <div className="message-banner">{message}</div>}

      {page === "menu" && (
        <>
          <Menu
            loading={loading}
            categories={categories}
            category={category}
            setCategory={setCategory}
            search={search}
            setSearch={setSearch}
            featuredFoods={featuredFoods}
            filteredFoods={filteredFoods}
            addToCart={addToCart}
          />

          <section className="section-gap cart-section">
            <div className="section-title-row">
              <div>
                <h2>Order Cart</h2>
                <p>Review items, waiting time, and continue to checkout.</p>
              </div>
            </div>

            {cart.length === 0 ? (
              <div className="empty-box">No items in cart.</div>
            ) : (
              <div className="cart-layout">
                <div className="cart-list-card">
                  {cart.map((item) => (
                    <div className="cart-item" key={item.id}>
                      <img
                        src={item.displayImage || getImageByFoodName(item)}
                        alt={item.name}
                        className="cart-thumb"
                      />

                      <div className="cart-main">
                        <h4>{item.name}</h4>
                        <p>₹{item.price} each</p>
                      </div>

                      <div className="qty-box">
                        <button onClick={() => updateQuantity(item.id, -1)}>-</button>
                        <span>{item.quantity}</span>
                        <button onClick={() => updateQuantity(item.id, 1)}>+</button>
                      </div>

                      <div className="cart-side">
                        <strong>₹{item.price * item.quantity}</strong>
                        <br />
                        <button
                          className="text-btn danger-text"
                          onClick={() => removeCartItem(item.id)}
                        >
                          Remove
                        </button>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="summary-card">
                  <h3>Bill Details</h3>

                  <div className="summary-line">
                    <span>Subtotal</span>
                    <span>₹{subtotal}</span>
                  </div>

                  <div className="summary-line">
                    <span>Packing Fee</span>
                    <span>₹{packingFee}</span>
                  </div>

                  <div className="summary-line">
                    <span>Platform Fee</span>
                    <span>₹{platformFee}</span>
                  </div>

                  <div className="summary-line">
                    <span>GST</span>
                    <span>₹{gst}</span>
                  </div>

                  <div className="summary-line total-line">
                    <span>Total</span>
                    <span>₹{totalAmount}</span>
                  </div>

                  <div className="wait-box">
                    Estimated waiting time: <strong>{waitingTime} mins</strong>
                  </div>

                  <button
                    className="primary-btn full-width-btn large-btn"
                    onClick={() => setShowCheckout(true)}
                  >
                    Proceed to Checkout
                  </button>
                </div>
              </div>
            )}
          </section>
        </>
      )}

      {page === "orders" && (
        <Orders apiBase={API_BASE} getStatusClass={getStatusClass} />
      )}

      {page === "admin" && (
        <Admin apiBase={API_BASE} onFoodSaved={loadFoods} />
      )}

      {showCheckout && (
        <div className="modal-backdrop" onClick={() => setShowCheckout(false)}>
          <div className="modal-card" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Checkout</h2>
              <button className="icon-btn" onClick={() => setShowCheckout(false)}>
                ✕
              </button>
            </div>

            <div className="checkout-grid">
              <div>
                <label>Student Name</label>
                <input
                  type="text"
                  name="customerName"
                  value={checkoutForm.customerName}
                  onChange={handleCheckoutChange}
                  placeholder="Enter your name"
                />
              </div>

              <div>
                <label>Payment Method</label>
                <select
                  name="paymentMethod"
                  value={checkoutForm.paymentMethod}
                  onChange={handleCheckoutChange}
                >
                  <option value="UPI">UPI</option>
                  <option value="Cash">Cash</option>
                  <option value="Card">Card</option>
                </select>
              </div>

              <div>
                <label>Order Type</label>
                <select
                  name="orderType"
                  value={checkoutForm.orderType}
                  onChange={handleCheckoutChange}
                >
                  <option value="Takeaway">Takeaway</option>
                  <option value="Dine-In">Dine-In</option>
                </select>
              </div>

              <div>
                <label>Pickup Slot</label>
                <select
                  name="pickupSlot"
                  value={checkoutForm.pickupSlot}
                  onChange={handleCheckoutChange}
                >
                  <option value="12:30 PM - 12:45 PM">12:30 PM - 12:45 PM</option>
                  <option value="12:45 PM - 01:00 PM">12:45 PM - 01:00 PM</option>
                  <option value="01:00 PM - 01:15 PM">01:00 PM - 01:15 PM</option>
                  <option value="01:15 PM - 01:30 PM">01:15 PM - 01:30 PM</option>
                </select>
              </div>
            </div>

            <div className="field-block">
              <label>Notes</label>
              <textarea
                rows="3"
                name="notes"
                value={checkoutForm.notes}
                onChange={handleCheckoutChange}
                placeholder="Less spicy, no onion, extra sauce, etc."
              />
            </div>

            {checkoutForm.paymentMethod === "UPI" && (
              <div className="checkout-summary-box">
                <div className="summary-line">
                  <span>UPI Payment</span>
                  <span>Scan QR below</span>
                </div>

                <div style={{ textAlign: "center", marginTop: "14px" }}>
                  <img
                    src={UPI_QR_IMAGE}
                    alt="UPI QR"
                    style={{
                      width: "170px",
                      height: "170px",
                      objectFit: "contain",
                      borderRadius: "12px",
                      background: "#fff",
                      padding: "10px"
                    }}
                  />
                  <p style={{ marginTop: "10px", color: "#cbd5e1" }}>
                    Scan and pay using any UPI app.
                  </p>
                </div>
              </div>
            )}

            <div className="checkout-summary-box">
              <div className="summary-line">
                <span>Total Items</span>
                <span>{totalItems}</span>
              </div>

              <div className="summary-line">
                <span>Total Amount</span>
                <span>₹{totalAmount}</span>
              </div>

              <div className="summary-line">
                <span>Waiting Time</span>
                <span>{waitingTime} mins</span>
              </div>

              <div className="summary-line">
                <span>Payment</span>
                <span>{checkoutForm.paymentMethod}</span>
              </div>

              <div className="summary-line">
                <span>Pickup</span>
                <span>{checkoutForm.pickupSlot}</span>
              </div>
            </div>

            <div className="modal-actions">
              <button
                className="secondary-btn"
                onClick={() => setShowCheckout(false)}
              >
                Back
              </button>
              <button className="primary-btn" onClick={placeOrder}>
                Place Order
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
